function RoseIcon({ color, size = 22 }: { color: string; size?: number }) {
  return (
    <svg
      width={size}
      height={size}
      viewBox="113 0 70 67"
      fill="none"
      aria-hidden="true"
      style={{ flexShrink: 0 }}
    >
      {ROSE_PATHS.map((d, i) => (
        <path key={i} d={d} fill={color} />
      ))}
    </svg>
  );
}

// Slimming brand color for the trigger chevron + divider
const SLIMMING_COLOR = '#8EB093';

export default function BrandSwitcher() {
  const [open, setOpen] = useState(false);
  const wrapRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!open) return;
    function handler(e: MouseEvent) {
      if (!wrapRef.current?.contains(e.target as Node)) setOpen(false);
    }
    document.addEventListener('mousedown', handler);
    return () => document.removeEventListener('mousedown', handler);
  }, [open]);

  useEffect(() => {
    function handler(e: KeyboardEvent) {
      if (e.key === 'Escape') setOpen(false);
    }
    document.addEventListener('keydown', handler);
    return () => document.removeEventListener('keydown', handler);
  }, []);

  return (
    <>
      <style>{`
        @keyframes bs-slim-drop {
          from { opacity: 0; transform: translateY(-6px) translateX(-50%); }
          to   { opacity: 1; transform: translateY(0)   translateX(-50%); }
        }
        .bs-slim-row { transition: background 0.15s; }
        .bs-slim-row:hover { background: var(--bs-hover-bg) !important; }
        .bs-slim-chevron { transition: transform 0.22s cubic-bezier(.22,1,.36,1); }
      `}</style>

      <div ref={wrapRef} style={{ position: 'relative', display: 'flex', alignItems: 'center' }}>

        {/* Vertical divider */}
        <div style={{
          width: 1,
          height: 18,
          background: 'rgba(142,176,147,0.4)',
          margin: '0 10px 0 8px',
          borderRadius: 1,
          flexShrink: 0,
        }} />

        {/* Chevron trigger */}
        <button
          onClick={() => setOpen(v => !v)}
          aria-label="Explore Carisma brands"
          aria-haspopup="true"
          aria-expanded={open}
          style={{
            background: 'none',
            border: 'none',
            cursor: 'pointer',
            padding: '6px 4px',
            display: 'flex',
            alignItems: 'center',
            color: SLIMMING_COLOR,
            lineHeight: 1,
          }}
        >
          <svg
            width="11"
            height="7"
            viewBox="0 0 11 7"
            fill="none"
            aria-hidden="true"
            className="bs-slim-chevron"
            style={{ transform: open ? 'rotate(180deg)' : 'rotate(0deg)' }}
          >
            <path
              d="M1 1L5.5 5.5L10 1"
              stroke="currentColor"
              strokeWidth="1.6"
              strokeLinecap="round"
              strokeLinejoin="round"
            />
          </svg>
        </button>

        {/* Dropdown panel */}
        {open && (
          <div
            role="dialog"
            aria-label="Carisma brand selector"
            style={{
              position: 'absolute',
              top: 'calc(100% + 14px)',
              left: '50%',
              transform: 'translateX(-50%)',
              width: 252,
              background: 'rgba(255,255,255,0.96)',
              backdropFilter: 'blur(20px) saturate(180%)',
              WebkitBackdropFilter: 'blur(20px) saturate(180%)',
              borderRadius: 14,
              boxShadow: '0 16px 48px rgba(40,55,44,0.11), 0 0 0 1px rgba(0,0,0,0.07)',
              overflow: 'hidden',
              zIndex: 1000,
              animation: 'bs-slim-drop 0.2s cubic-bezier(.22,1,.36,1) both',
            }}
          >
            {/* Brand rows */}
            {BRANDS.map((b, i) => (
              <a
                key={b.name}
                href={b.url}
                target="_blank"
                rel="noopener noreferrer"
                onClick={() => setOpen(false)}
                className="bs-slim-row"
                style={{
                  display: 'flex',
                  alignItems: 'center',
                  gap: 12,
                  padding: '14px 16px',
                  borderBottom: i < BRANDS.length - 1 ? '1px solid rgba(0,0,0,0.05)' : 'none',
                  textDecoration: 'none',
                  background: 'transparent',
                  ['--bs-hover-bg' as string]: `${b.color}09`,
                }}
              >
                <RoseIcon color={b.color} size={22} />
                <div style={{ flex: 1, minWidth: 0 }}>
                  <div style={{
                    fontFamily: '"Novecento Wide", "Helvetica Neue", sans-serif',
                    fontSize: 11,
                    fontWeight: 700,
                    letterSpacing: '0.28em',
                    textTransform: 'uppercase',
                    color: b.color,
                    lineHeight: 1,
                  }}>
                    CARISMA
                  </div>
                  <div style={{
                    fontFamily: '"Novecento Wide", "Helvetica Neue", sans-serif',
                    fontSize: 9,
                    fontWeight: 700,
                    letterSpacing: '0.22em',
                    textTransform: 'uppercase',
                    color: b.color,
                    opacity: 0.6,
                    marginTop: 4,
                    lineHeight: 1,
                  }}>
                    {b.name}
                  </div>
                </div>
                <svg
                  width="11"
                  height="11"
                  viewBox="0 0 11 11"
                  fill="none"
                  aria-hidden="true"
                  style={{ flexShrink: 0, opacity: 0.3 }}
                >
                  <path
                    d="M2 9L9 2M9 2H4.5M9 2V6.5"
                    stroke={b.color}
                    strokeWidth="1.5"
                    strokeLinecap="round"
                    strokeLinejoin="round"
                  />
                </svg>
              </a>
            ))}

            {/* Footer */}
            <div style={{
              padding: '8px 16px 9px',
              borderTop: '1px solid rgba(0,0,0,0.05)',
            }}>
              <span style={{
                fontFamily: '"Novecento Wide", "Helvetica Neue", sans-serif',
                fontSize: 8.5,
                letterSpacing: '0.14em',
                textTransform: 'uppercase',
                color: '#c8d4d4',
              }}>
                Carisma Wellness Group · Malta
              </span>
            </div>
          </div>
        )}
      </div>
    </>
  );
}
